package com.google.gson.reflect;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.mockito.Mockito.mock;

import org.junit.jupiter.api.Test;

import java.lang.reflect.Field;

public class TypeToken_hashCode_Test {

  @Test
  void hashCode_returnsPrecomputedHashCode() throws Exception {
    // Arrange
    // Create a mock TypeToken instance without calling constructor logic
    TypeToken<?> typeToken = (TypeToken<?>) java.lang.reflect.Proxy.newProxyInstance(
        TypeToken.class.getClassLoader(),
        new Class<?>[]{TypeToken.class},
        (proxy, method, args) -> {
          if ("hashCode".equals(method.getName())) {
            return TypeToken.class.getDeclaredField("hashCode").getInt(proxy);
          }
          return method.invoke(proxy, args);
        });

    // Use reflection to create an instance bypassing constructor
    java.lang.reflect.Constructor<TypeToken> constructor =
        TypeToken.class.getDeclaredConstructor(Type.class);
    constructor.setAccessible(true);
    TypeToken<?> instance = constructor.newInstance((Type) String.class);

    // Use reflection to get private field 'hashCode'
    Field hashCodeField = TypeToken.class.getDeclaredField("hashCode");
    hashCodeField.setAccessible(true);

    // Set a known hashCode value
    int expectedHashCode = 123456789;
    hashCodeField.setInt(instance, expectedHashCode);

    // Act
    int actualHashCode = instance.hashCode();

    // Assert
    assertEquals(expectedHashCode, actualHashCode);
  }
}
